package com.weib.controller;
import com.weib.dto.Result; import jakarta.servlet.http.HttpSession; import org.springframework.beans.factory.annotation.Value; import org.springframework.web.bind.annotation.*; import org.springframework.web.multipart.MultipartFile; import java.nio.file.*; import java.util.*;
@RestController @RequestMapping("/api/forum/media")
public class ForumMediaController { private final Path root; public ForumMediaController(@Value("${storage.upload-dir}")String dir){root=Paths.get(dir).toAbsolutePath().normalize();}
 @PostMapping public Result<Map<String,Object>> upload(@RequestParam("file") MultipartFile file,HttpSession session)throws Exception{if(session==null||session.getAttribute("user")==null)throw new IllegalArgumentException("login required");if(file==null||file.isEmpty()||file.getSize()>10*1024*1024)throw new IllegalArgumentException("image invalid or too large");String ct=file.getContentType()==null?"":file.getContentType().toLowerCase();String ext=ext(file.getOriginalFilename(),ct);Path dir=root.resolve("forum").normalize();if(!dir.startsWith(root))throw new IllegalArgumentException("upload path invalid");Files.createDirectories(dir);String name=UUID.randomUUID()+ext;Path target=dir.resolve(name).normalize();file.transferTo(target);return Result.success(Map.of("url","/uploads/forum/"+name,"size",file.getSize()));}
 private String ext(String name,String ct){String n=name==null?"":name.toLowerCase();if(n.endsWith(".png")&&ct.equals("image/png"))return ".png";if((n.endsWith(".jpg")||n.endsWith(".jpeg"))&&ct.equals("image/jpeg"))return ".jpg";if(n.endsWith(".gif")&&ct.equals("image/gif"))return ".gif";if(ct.equals("image/webp"))return ".webp";throw new IllegalArgumentException("image format invalid");}}
